INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027a2be3c98b0941765865', '中秋节入住花园酒店，一进门就被金碧辉煌的大堂吸引，酒店后花园特别漂亮，花园酒店房间很大也很不错，预定套餐还送了下午茶和行政待遇特别好，特别是行政待遇Carrie和Kitty服务好，早餐也可以在30楼吃，特别丰富，酒店历史悠久很不错满意满意推荐', '["https://dimg04.c-ctrip.com/images/0231312000fojfchpB38E_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231j12000fojet9700EA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236i12000fojgmv7409D_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232512000fojf26k8667_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236y12000fojh3w2B64D_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232312000fojgmvd9622_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230x12000fojejkuAAD6_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-21', '花园双床房', '双床房', '家庭亲子', 121, 0, 5, 8, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027a2be3c98b0941765866', '这是第二次入住花园酒店～中秋节假期定了两间房庆祝，从入住前Call center的服务，到入住当天起前台、礼宾、客房等的服务都让人体验感非常好！！下次来广州还会再来住的～希望未来花园酒店能成为我在广州的唯一选择。', '["https://dimg04.c-ctrip.com/images/0232012000gfwofsiE87A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000gfw3qnt6879_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000gfwmgq4D714_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-02', '粤韵大床套房', '套房', '家庭亲子', 106, 0, 1, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027a2be3c98b0941765867', '感受三十九年历史的五星白金酒店，瀑布花园，酒店历史博物馆，服务也很棒！30楼行政酒廊，旋转餐厅，远看小蛮腰和城市天际线，确实很美，尤其表扬工作人员小姐姐们：Carrie，Kitty，Cathy和Echo，服务热情周到，点赞！', '["https://dimg04.c-ctrip.com/images/0235612000flw34ha22B1_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236v12000flw2iwgA770_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236212000flw2nzrBFFC_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235612000flw38cuF4F5_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236312000flw38dcA72D_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233a12000flw3egpCA57_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232912000flw3405FCED_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-17', '花园双床房', '双床房', '家庭亲子', 112, 0, 2, 9, '["整体满意度","景观/朝向","前台服务"]'::jsonb, '整体满意度', '景观/朝向', '前台服务'),
('68027a2be3c98b0941765868', '不愧是中国铂金五星！', '["https://dimg04.c-ctrip.com/images/0233312000im51d9350B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000im5ios50AA4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000im5tt65B8B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000im5kmgk3A0F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-19', '花园大床房', '大床房', '商务出差', 10, 0, 19, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a2be3c98b0941765869', '环境不错的酒店。住得很舒服。房间高空还有景色看。服务也是不错的。早餐好吃的。吃完在花园散散步惬意的。', '["https://dimg04.c-ctrip.com/images/0235v12000g57lapv287A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000g57wdon813F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000g56so6iAFD5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000g57myq23041_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000g56qbwzA16C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000g57r2y48F5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000g5781j25B7D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000g579fsl847D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000g573lwyB471_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-15', '红棉大床套房', '套房', '商务出差', 50, 0, 30, 5, '["整体满意度","景观/朝向","餐饮设施"]'::jsonb, '整体满意度', '景观/朝向', '餐饮设施'),
('68027a2be3c98b094176586a', '花园酒店地理位置优越去哪里都很方便，酒店整体感觉高端大气不愧是广州的老牌五星级酒店！酒店环境也很好，有很大的后花园。房间整体也满意，服务人员都很有礼貌。中秋节期间入住还很贴心的给我们房间和朋友房间都送了月饼，周到大气！', '["https://dimg04.c-ctrip.com/images/0235y12000fmaa5io7C63_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000fmae0x6AAAB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000fm9tz7l4FD2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000fmacjwq454C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000fma87trF959_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000fmag0x7E3BF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-18', '花园大床房', '大床房', '家庭亲子', 109, 0, 1, 9, '["交通便利性","整体满意度","前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务'),
('68027a2be3c98b094176586b', '酒店各方面都非常满意，因为普通双床隐私性不太好，看我带着儿子，主动给我升级了房间，客务中心小颜的服务也很nice ，总之都满意！下次去广州还会选择这里??', '["https://dimg04.c-ctrip.com/images/0230412000jls4che4CC0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000jls3ur3426F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000jlrsjy1A6D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-06', '花园双床房', '双床房', '家庭亲子', 77, 0, 7, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027a2be3c98b094176586c', '工作人员很热情，离地铁站近，出行方便。', '["https://dimg04.c-ctrip.com/images/0236j12000i86lg0q65EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-01', '花园大床房', '大床房', '家庭亲子', 19, 0, 126, 5, '["前台服务","交通便利性"]'::jsonb, '前台服务', '交通便利性', NULL),
('68027a2be3c98b094176586d', '酒店地理位置优越，环境好，早餐品种丰富，味道好，前台小姐姐YOLO安排的房间很完美，还送了花，行政酒廊很好吃，Carrie和Berlye以及Cathy三位小姐姐人美声甜，服务态度很好，以后来广州还会选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0233612000fkdtixp0AE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000fkdybj95261_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000fkdwtp66AC0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000fkdydpwCBEC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-15', '花园大床房', '大床房', '情侣出游', 106, 0, 6, 8, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027a36e3c98b094176586e', '房间整体布局非常人性化好用??全面提供不同的空间场景（寝室/客厅/办公/衣帽化妆间等等）环境干净，还提供不同风味的软包装饮品舒适如家??唯一对我个人来窗户不能打开安全　角度让窒内引入外界新鲜空气产生交换（纯粹我个人喜欢）在此我要称赞客服中心电话咨询服务的小华服务到位全方面介绍酒店各个餐厅的特色并特别推荐30楼的行政酒廊高雅格调非常适合小众商务活动??特别我在行政酒廊遇到的两位职员Cathy和Berdly业务知识够丰富，尤其Cathy对酒店各处环境如数家珍向我推荐必游的酒店博物馆??????和花园酒店的领南特色瀑布花园??????酒店泳池整体感觉不错希望提供一次性泳帽以满足酒店国际宾客入住??', '["https://dimg04.c-ctrip.com/images/0206212000fjg94gg2F30_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0203p12000fjg8u1c60BB_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0232x12000fjfiipf0718_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000fjg12d146FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000fjg1syvCA6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000fjfpg8l232A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000fjfnhr61E36_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000fjfgympC90E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000fjg14ut205F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000fjfngbx8EAA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-13', '花园大床房', '大床房', '独自旅行', 299, 0, 3, 9, '["房间设施","前台服务","公共设施"]'::jsonb, '房间设施', '前台服务', '公共设施'),
('68027a36e3c98b094176586f', '广交会起期间 每次都住花园酒店 服务很好 就是人太多早餐需要排队 这次给升级了套房 特别宽敞 还配有踏步机 虽然没使用 但感觉不错', '["https://dimg04.c-ctrip.com/images/0230d12000gh0777h87CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000gh07lceA893_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000gh07jx28AA4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-03', '城央绿意大床房', '大床房', '商务出差', 65, 0, 54, 8, '["整体满意度","房间设施","餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施'),
('68027a36e3c98b0941765870', '很棒的一次体验！
1、刚步入酒店，就被酒店的大堂设计惊艳到了，非常漂亮有特色。大堂里的服务人员很多，每个人都能热情的迎接。某些时段还有表演，小朋友很喜欢。
2、原本订的是大床房，办理入住的时候前台客服很惊喜的给升级了套房。房间里还送了欢迎水果，很丰富。
3、泳池和健身房设施齐全，工作人员也很尽心尽责。泳池边上还有两个按摩浴缸，是小朋友们的玩水乐园。
4、酒店4楼有个博物馆，国庆期间还有打卡活动，小朋友很喜欢，打卡完成还领取了小礼品。
5、酒店的后花园名不虚传，有小桥、瀑布和成群的锦鲤，景色很不错，是拍照的好地方。
6、打卡了荔湾亭，出品稳定，糯米鸡、菠萝包很好吃。
最后提一句，大堂左侧有个面包店，卖的面包很好吃！特别推荐苹果丹麦、菠萝丹麦！', '["https://dimg04.c-ctrip.com/images/0236h12000g19k64kB17B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000g19ds3gA12B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000g19jk6h59BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000g19lu0r0130_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000g19fk9sC555_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000g19sg9t4FAE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000g19elldF6F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000g19j1x48FAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000g19fhztC02C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-08', '花园大床房', '大床房', '家庭亲子', 324, 0, 20, 9, '["公共设施","前台服务","餐饮设施"]'::jsonb, '公共设施', '前台服务', '餐饮设施'),
('68027a36e3c98b0941765871', '非常漂亮的酒店，地理位置优越，房间宽敞、酒店有几个歺厅，酒吧也不错，还有个小小博物馆，是出游不错的选择', '["https://dimg04.c-ctrip.com/images/0236n12000guxhu7c1F26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000guxyukg52A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000guxhbg6AFAF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-25', '红棉双床套房', '套房', '朋友出游', 51, 0, 25, 6, '["整体满意度","周边配套","餐饮设施"]'::jsonb, '整体满意度', '周边配套', '餐饮设施'),
('68027a36e3c98b0941765872', '花园酒店每次出差都来 挺好的 不错不错不错错不错不错错不错不错错不错不错错不错不错错不错不错错不错不错好', '["https://dimg04.c-ctrip.com/images/0233i12000hvzzexnA013_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000hw054vt8E13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000hw0s4h3E525_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-18', '城央绿意大床房', '大床房', '商务出差', 52, 0, 23, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a36e3c98b0941765873', '大厅还挺震撼的，金碧辉煌，有很多外国人入住。泳池露天在四楼，水凉。性价比还是挺高的。有一个酒店博物馆，值得一看。瀑布在花园里，有一个挺大的花园。是一个有特色的酒店。', '["https://dimg04.c-ctrip.com/images/0231212000g0ibeht0AE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000g0ia39x6953_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000g0i7abh4875_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000g0iakmj48FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000g0igz3mA827_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000g0ih9so208D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000g0iaajzC7CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000g0i904j138A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000g0if8lb6D10_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-10-06', '花园双床房', '双床房', '家庭亲子', 82, 0, 6, 7, '["公共设施","性价比","整体满意度"]'::jsonb, '公共设施', '性价比', '整体满意度'),
('68027a36e3c98b0941765874', '床舒适，早餐一般。老字号', '["https://dimg04.c-ctrip.com/images/0231u12000iks495wDBC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000iksczo65595_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.6, 3, '2025-02-17', '花园大床房', '大床房', '家庭亲子', 12, 0, 4, 4, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027a36e3c98b0941765875', '前台帮忙升级的粤韵套房，楼层设的迎送岗，酒店的博物馆、瀑布餐厅的早餐、荔湾亭的夜茶氛围，一切都很美好。', '["https://dimg04.c-ctrip.com/images/0230g12000guix9c917DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000gujpc0i829D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000gujprqlD221_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-24', '花园双床房', '双床房', '情侣出游', 51, 0, 4, 8, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027a36e3c98b0941765876', '酒店环境一级棒，门前有澳门的感觉，一进大堂也很高大尚，有博物馆、游泳池，一楼瀑布餐厅环境很棒！但早餐没啥好吃的有点一般。唯一吐槽的就是房间太陈旧了，很破。其它都很好。', '["https://dimg04.c-ctrip.com/images/0234r12000g0wdsfk4CD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000g0w6kfc4462_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000g0whnvx2F7F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000g0wgjyeBC26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000g0wgjk406AB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-10-07', '花园双床房', '双床房', '家庭亲子', 83, 0, 7, 7, '["房间设施","公共设施","餐饮设施"]'::jsonb, '房间设施', '公共设施', '餐饮设施'),
('68027a36e3c98b0941765877', '原本只是想趁休息日舒缓一下身心，却没想到“花园”能带给我如此多的惊喜?????? 首先，check in时被告知我被升级至套房了。入住后，主管卫生的许经理更是给予了无微不至的关怀与照顾???? 使得一个人的旅行也倍感温暖???? “花园”的好，好在细节，好在服务，这是新派酒店无法做到的。每一样摆设都彰显心思，每一处地方都恰到好处，值得你去慢慢品味。房间很安静，酒店氛围也很轻松，它的管理也很人性化，根据房间情况给予延迟退房，简直颠覆了我对此概念的认知??。所以，不到“花园”，你是不会知道它有多好的，在此再次谢谢许经理，谢谢携程??????', '["https://dimg04.c-ctrip.com/images/0231312000g0khvdo5B5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000g0klwi0F0AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000g0kornc8053_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000g0k4gwo3AA9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000g0k0u27FAE4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-06', '城央绿意大床房', '大床房', '独自旅行', 271, 0, 6, 9, '["前台服务","整体满意度","安静程度"]'::jsonb, '前台服务', '整体满意度', '安静程度'),
('68027a40e3c98b0941765878', '一次定了三间房四晚，刚刚评价过了', '["https://dimg04.c-ctrip.com/images/0234r12000ibykn2iD84C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 16, 0, 13, 2, '[]'::jsonb, NULL, NULL, NULL),
('68027a40e3c98b0941765879', '朋友推介的历史悠久的酒店，酒店很特别很有特色，酒店大堂有本地和外籍的工作人员，每位服务态度都很好很耐心解答。吃自助晚餐的餐厅也考虑得比较周到，不管是外地的还是外籍的游客都有很多各地方的菜式，海鲜很新鲜很清甜，五成牛排稍微有点生吃得不是很习惯，其他菜式都很有特色，菜品看起来很有食欲。餐厅的不管是厨师还是外籍服务员服务态度都非常好，很热心很耐心，一开始提前了一天也没有预约到座位，但是告知可以先办理入住等到有座位入席吃饭再打电话通知我过来，不用本人在现场排队，这点做得很不错，对于我这种带小朋友的游客来说是很不错的用餐体验。
房间的卫生也做得很好，浴缸也比其他酒店做得更方正一些，很适合带小孩住，洗浴都比较方便。特意带小朋友逛了花园酒店的几十年历史的博物馆，很有意义的一次住宿体验！4楼的泳池也很不错，大夏天在泳池游泳玩玩水枪也是个很棒的选择。
有一点不怎么好的就是，从酒店大堂去地下停车场没有指示牌，要询问工作人员才知道怎么走。酒店内的温度太低了，一进门就感觉到很冷要穿多件小外套，和室外温度相差太多了，可以在原有的温度内稍微调高一些吗？', '["https://dimg04.c-ctrip.com/images/0236m12000fcdg83qDD95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000fcdup5u6A2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000fcdoyjl3128_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000fce78bwF6E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000fcdf42aB896_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000fce9f9f2476_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000fcdro6i0B64_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000fcdrker109C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000fcddphe43B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-09-01', '花园双床房', '双床房', '家庭亲子', 469, 0, 8, 9, '["餐饮设施","客房服务","公共设施"]'::jsonb, '餐饮设施', '客房服务', '公共设施'),
('68027a40e3c98b094176587a', '花园酒店不愧为城市的名片，与普通五星级级酒店更多了一份城市的印记与温度。就连洗手间的一堵墙都有木棉花的画，处处都有设计。后花园更是别有洞天。', '["https://dimg04.c-ctrip.com/images/0234p12000g8ej8lz3BE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000g8ed4hf8347_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000g8eilm25E68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000g8ednqe85DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-10-21', '红棉双床套房', '套房', '家庭亲子', 70, 0, 8, 8, '["整体满意度","房间设施","公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施'),
('68027a40e3c98b094176587b', '小时候家里人带着去参观，认识了啥叫五星级大酒店，心里面五星级的形象。服务没的说，工作人员都很有礼貌，干净卫生。就是老牌酒店了，设施多少有点陈旧，隔音有点一般。', '["https://dimg04.c-ctrip.com/images/0234x12000g153dto8B1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000g1530fw7240_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000g156qg48115_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000g15122e44A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000g157hos67D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000g14ybxr1A97_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-08', '花园大床房', '大床房', '独自旅行', 79, 0, 6, 7, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('68027a40e3c98b094176587c', '一次愉快的入住体验！', '["https://dimg04.c-ctrip.com/images/0230c12000igou4mm30B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-11', '城央绿意双床房', '双床房', '家庭亲子', 10, 0, 9, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a40e3c98b094176587d', '花园饭店，不亏是老牌白金五星酒店，工作人员训练有素礼貌热情，大堂非常大气，房间舒适雅致。这次我是带着家人入住，一共订了三家房间，因为一如既往有回家的感觉，家人们都非常满意，果断又续住了两天。另外酒店旁边挨着地铁，出行也很方便。到广州选择花园酒店，一定会给大家带来心灵上的愉悦，强烈推荐入住。这里顺便特别感谢前台经理吴灵伶和Justin, 办理入住时，由于自己操作有误少订了一个房间，他们及时帮我与携程联络，第一时间解决了问题。我爱花园饭店，下次来广州一定还是选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0234j12000jbae4ukA18F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000jbadpe3B685_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000jba8qszA690_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000jba8drxD206_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000jba8mko5C37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-25', '花园双床房', '双床房', '家庭亲子', 236, 0, 1, 9, '["前台服务","整体满意度","交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性'),
('68027a40e3c98b094176587e', '广州花园酒店历史悠久位置优越交通便利，环境优美宜人。卫生整洁先进。服务周到热情，升级后的房间更是宽敞舒适明亮，入住体验完美。', '["https://dimg04.c-ctrip.com/images/0233812000gosqxo3EE0E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000gorwuqt1AC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000gosm5rh2AB0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-15', '花园大床房', '大床房', '朋友出游', 62, 0, 11, 7, '["整体满意度","交通便利性","卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况'),
('68027a40e3c98b094176587f', '服务超棒，下次还是会选花园酒店', '["https://dimg04.c-ctrip.com/images/0236l12000ikdvl0m6AEB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000ikddjm6F4E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000ikddjm8E3EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-17', '花园大床房', '大床房', '家庭亲子', 15, 0, 3, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a40e3c98b0941765880', '房间布局合理，比红棉大床房少了会客厅，两个人广州旅游足够了，位置很便利，去哪里都很方便，出门就是淘金地铁站，30楼的行政酒廊早餐和下午茶都很丰盛，味道也好，还是个城市旋转观景台，挺有意思。行政酒廊的echo服务很好，点名表扬??', '["https://dimg04.c-ctrip.com/images/0231112000fe1ucrrA4A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000fe1571dDBD2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000fe1lbz542EA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-04', '花园大床房', '大床房', '情侣出游', 114, 1, 1, 8, '["交通便利性","餐饮设施","前台服务"]'::jsonb, '交通便利性', '餐饮设施', '前台服务'),
('68027a40e3c98b0941765881', '酒店升级了房型，酒店地处市中心，闹中取静，出行方便，房间宽敞，干净整洁，很是舒适，出差一直选花园酒店，熟悉的地方很有安全感', '["https://dimg04.c-ctrip.com/images/0230k12000gejs3h5EC77_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000gejfgir9AFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000gejmgx94D6E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-31', '花园大床房', '大床房', '商务出差', 61, 0, 1, 7, '["整体满意度","交通便利性","安静程度"]'::jsonb, '整体满意度', '交通便利性', '安静程度'),
('68027a4de3c98b0941765882', '服务非常好，酒店环境也很好，尤其是自带一个花园，有曲径通幽的感觉，瀑布花园、30层的旋转餐厅环境都不错。整体装修啥的会稍微有一点老，毕竟是早批的五星酒店。', '["https://dimg04.c-ctrip.com/images/0232912000g0fj6zyB536_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000g0fzwun218A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000g0fj70026F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000g0fv19k75E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000g0fob26CB52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000g0fxiga0C9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000g0fj81g2CD6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000g0fjxfz4D1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-06', '花园大床房', '大床房', '其他', 77, 0, 2, 8, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68027a4de3c98b0941765883', '第3次入住酒店了，离地铁口很近，酒店有专门的停车场，解决了在广州这里停车这个头疼事。地点很方便周边吃喝玩很多选择。房间虽然不大，服务，特别好，很舒适。因为有老人特意换了没有浴缸的冲凉房。', '["https://dimg04.c-ctrip.com/images/0234m12000fh2miw86E68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000fh2smsm2BD9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000fh2rxkz66B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-09', '花园双床房', '双床房', '家庭亲子', 93, 0, 5, 8, '["交通便利性","周边配套","房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施'),
('68027a4de3c98b0941765884', '来之前特意查了酒店的历史，特别有历史感的酒店，40年的历史，外管还是很有质感。我是冲着贝隶铭去的，名设计师的手笔。酒店有一个花园，挺有格调的，孩子在花园喂鱼，可以玩挺久。这里有很多的外国人入住，服务员的态度非常棒。说一下不足的地方，酒店房间设施确实比较旧了，但是有一说一，几十年的酒店，设备要求肯定不如新酒店。酒店的浴室设计比较奇怪，浴室没有地方挂衣服，出来洗手盆那里穿的话，其实通过对面的镜子会被房间的人看到。说一下地理位置，非常优越，地铁五号线一分钟路程，去各大景点路程都不算远。房费在这个地点不算贵了，所以大家可以根据自己的需求选择。', '["https://dimg04.c-ctrip.com/images/0236j12000fbyoyek0BC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000fbyluahBCFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000fbynf2r2EAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000fbyk5m609F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000fbyrahiDCEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000fbyp13aED08_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-31', '花园双床房', '双床房', '家庭亲子', 270, 0, 12, 9, '["房间设施","交通便利性","性价比"]'::jsonb, '房间设施', '交通便利性', '性价比'),
('68027a4de3c98b0941765885', '房间安排非常舒适，卫生整理及时。酒店后花园让人感到温暖、温馨??；早餐丰富、服务生态度绝对到位。值得推荐！', '["https://dimg04.c-ctrip.com/images/0234x12000gmbgp2379D1_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234m12000gmbghb4764B_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235312000gmbgm8u1005_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233712000gmbgd58F0EC_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-11-11', '花园大床房', '大床房', '家庭亲子', 53, 0, 4, 7, '["整体满意度","客房服务","餐饮设施"]'::jsonb, '整体满意度', '客房服务', '餐饮设施'),
('68027a4de3c98b0941765886', '酒店氛围很好，亲子游合适', '["https://dimg04.c-ctrip.com/images/0231i12000ibf7nso9105_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 12, 0, 5, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a4de3c98b0941765887', '太暖心了，服务超级好，值得你们预定', '["https://dimg04.c-ctrip.com/images/0234c12000hwj96rk97A7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-01-19', '城央绿意双床房', '双床房', '家庭亲子', 17, 0, 5, 3, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027a4de3c98b0941765888', '假期就是吃吃喝喝的时候，又来花园酒店了。前台姐姐热情地将我的红棉房升级到粤韵房，两张1.3米的床，体验感更好。洗漱台有两个，干湿分离且两人不干扰。酒店服务员都热情好客，让人如沐春风。在荔湾亭订位后进了晚餐，环境和服务都很不错，出品也物有所值。酒店还有个博物馆，可以了解酒店的辉煌历史。早餐种类很丰富，整体是很好的体验，值得再去。', '["https://dimg04.c-ctrip.com/images/0234p12000fbxfun69C6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000fbx9pv65BAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000fbx9uz59CCD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000fbxcnvw7BAA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-31', '红棉双床套房', '套房', '家庭亲子', 164, 0, 1, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027a4de3c98b0941765889', '很感谢花园酒店前台的热情接待，给我升级安排的房间安静舒适，酒店的设施和服务让我感到宾至如归。房间宽敞明亮，床铺舒适，让我得以安享良好的睡眠。此外，每到一处的员工都有着热情服务和细致入微的照顾让我倍感温馨。酒店还提供了丰富的自助早餐和各种休闲设施，令我倍感放松。花园酒店是老广州的五星酒店，亦是广州的地标，在某些人的心里是一个时代无法磨灭的记忆！', '["https://dimg04.c-ctrip.com/images/0233u12000ew91ayf2E31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000ew946yiD273_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000ew93dr832F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000ew938zl7BA4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000ew92er519B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000ew92h6mCD3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000ew935lz3D5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000ew91ayh90F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000ew93bfuD5AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-25', '花园双床房', '双床房', '商务出差', 172, 5, 21, 9, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027a4de3c98b094176588a', '值得推荐，博物馆可以看看', '["https://dimg04.c-ctrip.com/images/0233u12000i69tgu28CB1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000i6brgir4DE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000i6brgr37934_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-30', '花园双床房', '双床房', '家庭亲子', 12, 0, 8, 3, '["整体满意度","周边配套"]'::jsonb, '整体满意度', '周边配套', NULL),
('68027a4de3c98b094176588b', '很多年没有入住花园了，装修很有中国特色，房间大，还给我升级房型，特别喜欢瀑布花园，是城市里的一个绿洲，服务员很细心', '["https://dimg04.c-ctrip.com/images/0234s12000gjzkzgz07BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000gk09bej3229_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000gjz86khE5F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000gk0dn5f51C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000gjzj28k5022_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000gk0ih7eEDD3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000gjzrpwlE9FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000gjzvag93853_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-07', '花园大床房', '大床房', '商务出差', 57, 0, 9, 7, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68027a5ee3c98b094176588c', '布置的很有新年气氛', '["https://dimg04.c-ctrip.com/images/0235n12000iawqq4b00C9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 9, 0, 26, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a5ee3c98b094176588d', '这次携家人入住广州花园酒店，感觉非常好，住宿环境非常好，菜品精致，味道好，孩子们对游泳池更是喜欢，总之，体验很好。再有，感谢行政酒廊的Kitty,Deepa，Beryle ，Cunchan四位小姐姐的热情服务。', '["https://dimg04.c-ctrip.com/images/0236c12000fb6oo365CBC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000fb6rrmx3403_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000fb6r5mj85F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000fb6oqxp68A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-30', '花园大床房', '大床房', '家庭亲子', 105, 0, 5, 7, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68027a5ee3c98b094176588e', '超出预期的酒店！酒店大堂，园景很漂亮，工作人员热情，前台还帮忙升级了房型，很惊喜。
我们带着小孩连住两个晚上，小孩子很喜欢。
体验了位于30层的行政酒廊，服务很好，餐食也很棒，可以远眺小蛮腰，强烈推荐。还要感谢行政酒廊Echo, Cathy, Bergle的热情服务~', '["https://dimg04.c-ctrip.com/images/0235w12000fceepdmAE58_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-01', '花园大床房', '大床房', '家庭亲子', 134, 1, 16, 8, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68027a5ee3c98b094176588f', '第一次开到花园，感受到十分浓厚的白金五星底蕴，外国友人很多，一片祥和，门口就是淘金A口，出行十分方便，对面有广州友谊商场和丽柏，购物也是相当的方便，期待下次再来', '["https://dimg04.c-ctrip.com/images/0232w12000fpre35iC0F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000fprjiuxC247_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000fprk38e0E35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000fprzn3eCB62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000fps2a7zFBCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000fpscmbe9583_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000fpryg9kBD2C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-23', '花园大床房', '大床房', '情侣出游', 80, 0, 19, 8, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027a5ee3c98b0941765890', '一如既往的好，喜欢。床特别舒服。环境也好。早餐也丰富', '["https://dimg04.c-ctrip.com/images/0231h12000heo245i7CCF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000henggyxCBCC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000hemqlwk376E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-25', '花园双床房', '双床房', '朋友出游', 26, 0, 65, 5, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027a5ee3c98b0941765891', '买的携程的套餐，红棉房有一房一厅，淋浴室有浴缸，也有花洒，分开的。房间很干净。宝宝过生日，提前打电话说明还送了蛋糕。酒店自带后花园+博物馆，大厅富丽堂皇。在酒店就可以逛一天，晚上在日本餐厅吃的饭，用的套餐的400消费金额。晚上滴滴去花城汇看喷泉。一切都很完美', '["https://dimg04.c-ctrip.com/images/0233i12000f9mdvuc9DFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000f9m9pkn5A2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000f9lmjk1E30B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-27', '红棉大床套房', '套房', '家庭亲子', 129, 0, 9, 9, '["房间设施","整体满意度","客房服务"]'::jsonb, '房间设施', '整体满意度', '客房服务'),
('68027a5ee3c98b0941765892', '老牌五星，历史悠久，酒店保养的挺好，大堂富丽堂皇，园林设计很用心，值得一逛，四楼的酒店博物馆也很值得看看，总体是个很值得体验的酒店，酒店交通便利，地铁口就在旁边，唯一不足是酒店早餐普通，但是也能满足基本需求了', '["https://dimg04.c-ctrip.com/images/0232u12000fbnkfi0732C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000fbnkbaz4FD6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000fbnct51B820_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000fbnquf9F48E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-31', '城央绿意大床房', '大床房', '情侣出游', 104, 0, 7, 8, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027a5ee3c98b0941765893', '二十年后再次入住花园酒店，没有那年那月的惊艳，只有一些怀旧的回顾。重返二楼荔湾亭，再上30楼，还是满满的贴心服务。两点不太满意之处，房间二并一后大一些但格局不太好，特别浴室的镜子斑斑驳驳更有年代感；另外就是客房服务不到位和僵化，因床头插座不明显，昨天上午离店时遗漏充电器，昨晚想起打电话过去，第一通电话说服务员没有上报，等落实后再回电，当时我还寻思是否我放在行李箱，再次大寻找不果后，也未等到酒店回电。我只能再次打电话，此次我非常明确进行描述，登记后二十来分钟回电说找到。我让帮忙叫一个到付的闪送之类，回复只能顺丰到付或是自取，没有考虑客人因为没有充电器的不便。只是服务僵化的问题，缺乏变通。另外就是房间服务员没有及时上报失物，存在瑕疵；再之就是酒店接到电话后，存在回复不及时等，相对遗憾。', '["https://dimg04.c-ctrip.com/images/0234712000f97t4db1B11_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000f97klto2C88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000f97h4i0FBB2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-08-26', '红棉大床套房', '套房', '商务出差', 345, 0, 24, 8, '["客房服务","房间设施","整体满意度"]'::jsonb, '客房服务', '房间设施', '整体满意度'),
('68027a5ee3c98b0941765894', '酒店位置很方便，服务也很好，各种设施很全，二楼和三楼的餐厅也很不错，酒店有不少外国人，还有后面的瀑布和园子造景也相当不错，各方面都符合老牌酒店的水准，住的是套房，酒店通风要是再好些的话就更完美了', '["https://dimg04.c-ctrip.com/images/0234q12000fbywo8x3FAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-31', '红棉大床套房', '套房', '商务出差', 97, 0, 9, 8, '["周边配套","整体满意度","餐饮设施"]'::jsonb, '周边配套', '整体满意度', '餐饮设施'),
('68027a5ee3c98b0941765895', '五星级的服务值得点赞，虽然房间的装修有点旧，但是卫生，细节都有五星级标准，酒店大厅大气高级，每个楼层都配备服务人员开电梯，带了两个小孩，还免费送了两小孩的早餐及行政酒廊，入住体验好非常好，早餐瀑布餐厅和30楼的旋转餐厅，环境很好，餐食也很不错', '["https://dimg04.c-ctrip.com/images/0236012000f9wg7wj4D9A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000f9wuz8f5930_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000f9whqydFBD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 121, 0, 1, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027a69e3c98b0941765896', '环境服务都挺好的', '["https://dimg04.c-ctrip.com/images/0231q12000ib87myr55CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-05', '红棉大床套房', '套房', '家庭亲子', 8, 0, 9, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL)
 ON CONFLICT (_id) DO NOTHING;
